"use strict";parserFactory.register("readhive.org",()=>new ReadhiveParser);class ReadhiveParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...this.getTab(e,"releases").querySelectorAll("a")].map(ReadhiveParser.linkToChapter).reverse()}static linkToChapter(e){return{sourceUrl:e.href,title:e.querySelector("span.ml-1").textContent.trim()}}getTab(e,t){return[...e.querySelectorAll("main div[x-show]")].filter(e=>e.getAttribute("x-show")?.includes(t))?.pop()}findContent(e){return e.querySelector("main div.justify-center:not([x-data])")}extractTitleImpl(e){return e.querySelector("h1")}findChapterTitle(e){return e.querySelector("h1 strong")}customRawDomToContentStep(e,t){for(let e of t.querySelectorAll("div")){let t=[];for(let r of e.attributes)r.name.startsWith("@")&&t.push(r.name);for(let r of t)e.removeAttribute(r)}}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"div[x-data]"),super.removeUnwantedElementsFromContentElement(e)}findCoverImageUrl(e){return util.getFirstImgSrc(e,"main")}getInformationEpubItemChildNodes(e){const t=this.getTab(e,"about");return null==t?[]:[...t.querySelectorAll("p")]}}